#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *petrol = (long long*)malloc(N * sizeof(long long));
        long long *cost   = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &petrol[i]);
        for (int i = 0; i < N; ++i) scanf("%lld", &cost[i]);
        long long totalPetrol = 0, totalCost = 0;
        for (int i = 0; i < N; ++i) {
            totalPetrol += petrol[i];
            totalCost   += cost[i];
        }
        if (totalPetrol < totalCost) {
            printf("-1\n");
            free(petrol); free(cost);
            continue;
        }
        long long tank = 0;
        int start = 0;
        for (int i = 0; i < N; ++i) {
            tank += petrol[i] - cost[i];
            if (tank < 0) {
                start = i + 1;
                tank = 0;
            }
        }
        printf("%d\n", start);
        free(petrol); free(cost);
    }
    return 0;
}

