import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            long[] petrol = new long[N];
            long[] cost = new long[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) petrol[i] = Long.parseLong(st.nextToken());
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) cost[i] = Long.parseLong(st.nextToken());
            long totalPetrol = 0, totalCost = 0;
            for (int i = 0; i < N; i++) { totalPetrol += petrol[i]; totalCost += cost[i]; }
            if (totalPetrol < totalCost) {
                sb.append(-1).append('\n');
                continue;
            }
            long tank = 0; int start = 0;
            for (int i = 0; i < N; i++) {
                tank += petrol[i] - cost[i];
                if (tank < 0) { start = i + 1; tank = 0; }
            }
            sb.append(start).append('\n');
        }
        System.out.print(sb.toString());
    }
}

